-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH insert_data AS (
    SELECT * FROM {{ ref('int_dim_equipment_router') }}
    WHERE router_group = 'INSERT'
),

max_id AS (
    SELECT COALESCE(MAX(DIM_EQUIPMENT_ID), 0) AS max_dim_equipment_id
    FROM {{ ref('stg_dim_equipment') }}
    WHERE EDW_CURRENT_FLG = 'Y'
),

insert_with_ids AS (
    SELECT
        i.*,
        m.max_dim_equipment_id,
        ROW_NUMBER() OVER (ORDER BY EQPUN_NBR, MARK_CD) AS row_seq
    FROM insert_data i
    CROSS JOIN max_id m
)

SELECT
    max_dim_equipment_id + row_seq AS DIM_EQUIPMENT_ID,
    NULL AS EDW_SRC_BPK_MD5_ID,
    NULL AS EDW_SRC_BK_MD5_ID,
    '{{ var("repository_user_name", "dbt_user") }}' AS EDW_CREATE_USER,
    CURRENT_TIMESTAMP() AS EDW_CREATE_TMS,
    '{{ var("repository_user_name", "dbt_user") }}' AS EDW_UPDATE_USER,
    CURRENT_TIMESTAMP() AS EDW_UPDATE_TMS,
    IFF(
        TYPE_2_FLG = '2' AND I_U_FLG != 'I',
        DATEADD('SECOND', 1, TYPE2_END_EFFECTV_DT),
        IFF(BUILT_DT IS NULL, RECORD_CREATE_TMS, BUILT_DT)
    ) AS EDW_START_EFCTV_DT,
    NULL AS EDW_END_EFCTV_DT,
    IFF(SRC_REGSTRD = 'N', 'N', 'Y') AS EDW_CURRENT_FLG,
    EQPUN_NBR,
    MARK_CD,
    IFF(AAR_CAR_CD IS NULL, 'N/A', AAR_CAR_CD) AS AAR_CAR_CD,
    AAR_CAR_CODE_ID AS AAR_CAR_CD_ID,
    EQPMNT_GROUP_CD,
    AXLE_QTY,
    BUILT_DT,
    DMTR_UOM_BASIS_CD,
    EIN_NBR,
    GROSS_WEIGHT_QTY,
    GROSS_WEIGHT_UOM_BASIS_CD,
    LINEAL_FRCTNL_UOM_BASIS_CD,
    LINEAL_UOM_BASIS_CD,
    LIQUID_UOM_BASIS_CD,
    OTSD_EXTRM_HEIGHT_QTY,
    OTSD_EXTRM_WIDTH_QTY,
    OTSD_HEIGHT_EXTRM_WIDTH_QTY,
    OTSD_LENGTH_QTY,
    OWNER_MARK_CD,
    o_LESSEE_MARK_CD AS LESSEE_MARK_CD,
    PRIOR_EQPUN_NBR,
    PRIOR_MARK_CD,
    SPEED_UOM_BASIS_CD,
    STATUS_CD,
    SRVC_LIFE_CD,
    STNCL_MARK_OWNER_CLASS_CD,
    TARE_WEIGHT_QTY,
    VOLUME_UOM_BASIS_CD,
    WEIGHT_UOM_BASIS_CD,
    MCHNCL_DSGNTN_CD,
    PLATE_CLRNC_CD,
    RBLT_CD,
    RBLT_DT,
    RATE_CD,
    CAR_OWNERSHIP,
    LEASED_IND,
    lkp_TARGET_EQPMT_CTGRY_NM AS TARGET_EQPMT_CTGRY_NM,
    lkp_PRDCT_NM AS PRDCT_NM,
    lkp_FLEET_NM AS FLEET_NM,
    lkp_EQPMNT_POOL_ID AS EQPMNT_POOL_ID,
    lkp_FLEET_SBGRP_CTGRY_NM AS FLEET_SBGRP_CTGRY_NM,
    lkp_PARTY_NM AS PARTY_NM,
    o_CAR_KIND_CD AS CAR_KIND_CD,
    UCA_CODES,
    CPR_EQPMT_POOL_ID AS CPR_EQPMNT_POOL_ID,
    AAR_EQPMNT_POOL_ID,
    EFCTV_TMS,
    EFCTV_TMS AS MAX_EFCTV_TMS,
    REGISTERED_IND,
    CP_OWNED_IND,
    DLTD_TMS
FROM insert_with_ids
